UndefinedDocblockClass.code:
if ($ordersElement = $this->structureManager->getElementByMarker('orders')) {
            $limit = 30;

            $days = $ordersElement->getTotalOrdersByDay($limit);

            $labels = [];
            $data = [];

            for ($i = $limit; $i >= 0; $i--) {
                $date = date('Y-m-d', strtotime('today - ' . $i . ' days'));
                $labels[] = $date;
                if (isset($days[$date])) {
                    $data[] = $days[$date];
                } else {
                    $data[] = 0;
                }
            }

            return json_encode([
                1 => [
                    'labels' => $labels,
                    'data' => $data,
                ],
            ]);
        }

